+    #[test]
+    fn verify_chain_gap_at_end() {
+        let e0 = genesis_entry();
+        let e1 = chain_entry(1, "entry-0");
+        let mut e5 = chain_entry(5, "entry-1");
+        e5.id = "entry-5".to_string();
+        let report = verify_chain(&[e0, e1, e5], None, None);
+        assert!(report.status.is_fail());
